import './App.css';
import ShapeGrid from './component/ShapeGrid';

function App() {
  return (
    <div className="App">
      <div className="shapegrid-shell">
        <ShapeGrid
          speed={0.5}
          squareSize={40}
          direction="diagonal"
          borderColor="#eedede"
          hoverFillColor="#000000"
          shape="square"
          hoverTrailAmount={0}
        />
      </div>
    </div>
  );
}

export default App;
